const items = Object.values($input.all());
const results = [];

// Keywords for high-intent sales leads
const salesRoles = ["AE", "Account Executive", "SDR", "BDR", "Sales", "Business Development", "Founder"  ,"sales",
  "sales coach",
  "head of sales",
  "vp",
  "vice president",
  "fractional",
  "revenue",
  "gtm",
  "go-to-market",
  "outbound",
  "cold",
  "ai"];

for (const item of items) {
  const p = item.json;

  // 1. ROLE FILTER: Ensure they are in sales/leadership
  const headline = (p.headline || "").toLowerCase();
  const isSalesPro = salesRoles.some(role => headline.includes(role.toLowerCase()));

  // 2. ENGAGEMENT POTENTIAL: 
  // We prioritize people with >500 connections (active) OR Premium accounts
  const isActiveUser = (p.connectionsCount > 500) || p.premium === true;

  // 3. TARGETING "PRACTITIONERS":
  // We actually filter OUT people with massive follower counts (>100k) 
  // because their comment sections are too crowded for you to stand out.
  const isAccessible = (p.followerCount || 0) < 50000;

  if (isSalesPro && isActiveUser && isAccessible) {
    const jobTitle = (p.experience && p.experience[0] && p.experience[0].position) || p.headline || "";
    results.push({
      json: {
        linkedinUrl: p.linkedinUrl || "",
        firstName: p.firstName || "",
        lastName: p.lastName || "",
        followersCount: p.followerCount || 0,
        // Grabbing the first current position title or falling back to headline
        title: (p.currentPosition && p.currentPosition[0] && p.currentPosition[0].position) || p.headline || "",
        role:jobTitle
      }
    });
  }
}

return results;

