// Get the items from the previous node
const items = Object.values($input.all());
const results = [];

// Use a Map to track unique leads and combine comments
const uniqueLeads = new Map();

for (const item of items) {
  const rawData = item.json;
  const p = rawData.actor || {}; 

  if (!p.firstName && !p.lastName) continue; 

  // 1. URL Normalization (Handles Emojis/Special Chars in links)
  const rawUrl = p.linkedinUrl || "";
  const cleanLinkedinUrl = encodeURI(rawUrl);

  // 2. Extract Comment
  const currentComment = rawData.commentary || "";

  // 3. DEDUPLICATION & AGGREGATION LOGIC
  if (uniqueLeads.has(cleanLinkedinUrl)) {
    // Lead exists: Just add the new comment to their existing record
    const existingLead = uniqueLeads.get(cleanLinkedinUrl);
    if (currentComment) {
      existingLead.json.comment += `\n---\n${currentComment}`;
    }
    continue; 
  }

  // 4. Clean Names (Remove emojis for professional CRM/Sheet use)
  const cleanFirstName = (p.firstName || "").replace(/[^\p{L}\p{N}\s]/gu, '').trim();
  const cleanLastName = (p.lastName || "").replace(/[^\p{L}\p{N}\s]/gu, '').trim();

  // 5. Get Professional Role and Company
  // Priority: experience[0] -> currentPosition[0] -> headline
  const role = (p.experience && p.experience[0] && p.experience[0].position) || p.headline || "Professional";
  const company = (p.experience && p.experience[0] && p.experience[0].companyName) || 
                  (p.currentPosition && p.currentPosition[0] && p.currentPosition[0].companyName) || "N/A";

  // 6. Link Hunter (Search profile button AND the 'About' section for URLs)
  const aboutText = p.about || "";
  const urlRegex = /(https?:\/\/[^\s]+)/g;
  const foundLinksInAbout = aboutText.match(urlRegex) || [];
  const website = (p.profileActions && p.profileActions[0] && p.profileActions[0].url) || foundLinksInAbout[0] || "NA";

  // 7. Create Lead Entry
  const leadEntry = {
    json: {
      linkedinUrl: cleanLinkedinUrl,
      firstName: cleanFirstName,
      lastName: cleanLastName,
      fullName: `${cleanFirstName} ${cleanLastName}`,
      role: role,
      company: company,
      companyWebsite: website,
      comment: currentComment,
      followersCount: p.followerCount || 0,
      premiumUser: p.premium || false
    }
  };

  // Store in Map using the URL as the key
  uniqueLeads.set(cleanLinkedinUrl, leadEntry);
}

// Convert the Map back to n8n's expected array format
return Array.from(uniqueLeads.values());

// 1. Get Hunter data for the CURRENT item being processed
const hunterResponse = $input.item.json;

if (!hunterResponse || !hunterResponse.data) {
    return { built_email: "No Data Available", domain: "N/A" };
}

const hunterData = hunterResponse.data;
const domain = hunterData.domain || "N/A";
const pattern = hunterData.pattern;

// 2. Get the lead's name dynamically
// Using $item(0) inside a Code node helps map the current input to the correct parent node data
const sheetNode = $("Scraped Leads Data").item.json; 
let first = (sheetNode["First Name"] || "").toLowerCase().trim();
let last = (sheetNode["Last Name"] || "").toLowerCase().trim();

let email = "";

// 3. Logic: Pattern vs Fallback
if (pattern && first && last) {
    if (pattern === "{first}.{last}") {
        email = `${first}.${last}@${domain}`;
    } else if (pattern === "{f}{last}") {
        email = `${first[0]}${last}@${domain}`;
    } else if (pattern === "{first}{last}") {
        email = `${first}${last}@${domain}`;
    } else if (pattern === "{first}") {
        email = `${first}@${domain}`;
    }
} 

// 4. Final Fallback
if (!email || email === "") {
    if (hunterData.emails && hunterData.emails.length > 0) {
        email = hunterData.emails[0].value; 
    } else {
        email = "No Data Available";
    }
}

return { 
    built_email: email, 
    source_domain: domain,
    pattern_used: pattern || "Generic Fallback",
    debug_name: `${first} ${last}` // This helps you see it's working!
};

const item = $input.item.json;
const status = item.email_deliverability.status;
const score = item.email_quality.score;
const isRole = item.email_quality.is_role;

let trustLevel = "";

if (status === "deliverable" && score > 0.8 && !isRole) {
    trustLevel = "Tier 1: Verified Personal";
} else if (status === "deliverable" && isRole) {
    trustLevel = "Tier 2: Verified Generic";
} else if (status === "catch_all") {
    trustLevel = "Tier 3: Unverifiable (Catch-all)";
} else {
    trustLevel = "Discard";
}

return {
    trust_level: trustLevel
};

